    4: {"user_id": 4, "role": "user"}
}


def is_admin(user_id: int) -> bool:
    """
    Return True if the given user_id corresponds to a user with the 'admin' role, else False.
    """
    user = USERS.get(user_id)
    if not user:
        return False
    return str(user.get("role", "")).lower() == "admin"

